<?php use function App\Core\{e,url,csrf_field}; ?><section class="grid"><?php foreach(['fanza'=>'FANZA','sokmil'=>'ソクミル','duga'=>'DUGA'] as $key=>$label): ?><div class="card"><h2><?= $label ?> API</h2><form method="post" action="<?= e(url('/settings/api')) ?>"><?= csrf_field() ?><input type="hidden" name="service" value="<?= $key ?>"><?php foreach(($key==='fanza'?['api_id','affiliate_id']:($key==='duga'?['appid']:['affiliate_id','endpoint'])) as $field): ?><label><?= e($field) ?><input name="credentials[<?= e($field) ?>]" value="<?= e($settings[$key][$field]??'') ?>"></label><?php endforeach; ?><button class="primary">保存</button></form></div><?php endforeach; ?></section><section class="card"><h2>ハッシュタグNGワード</h2><form method="post" action="<?= e(url('/settings/ng-words')) ?>"><?= csrf_field() ?><textarea name="ng_words" rows="8" placeholder="1行に1語"><?= e($ngWords) ?></textarea><button class="primary">保存</button></form></section>
